import{_ as e,o as l,c as a,a2 as n}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"F10: 成本結構與經營槓桿門檻 — 良維 (6290)","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6290_良維/20260424/F10_成本結構與經營槓桿門檻_財務分析專家.md","filePath":"審計報告庫/財務審計/6290_良維/20260424/F10_成本結構與經營槓桿門檻_財務分析專家.md"}'),r={name:"審計報告庫/財務審計/6290_良維/20260424/F10_成本結構與經營槓桿門檻_財務分析專家.md"};function d(i,t,s,g,o,x){return l(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="f10-成本結構與經營槓桿門檻-—-良維-6290" tabindex="-1">F10: 成本結構與經營槓桿門檻 — 良維 (6290) <a class="header-anchor" href="#f10-成本結構與經營槓桿門檻-—-良維-6290" aria-label="Permalink to &quot;F10: 成本結構與經營槓桿門檻 — 良維 (6290)&quot;">​</a></h1><blockquote><p><strong>審計日期</strong>：2026-04-24 <strong>專家角色</strong>：財務分析師 (<code>finance-financial-analyst</code>) <strong>標的公司</strong>：良維科技 (LONGWELL, 6290.TWO) — 電子零組件業 <strong>核心分析</strong>：成本習性拆解、損益平衡點測算、經營槓桿係數 (DOL) 量化、景氣承壓測試</p></blockquote><hr><h2 id="【專家直斷】" tabindex="-1">【專家直斷】 <a class="header-anchor" href="#【專家直斷】" aria-label="Permalink to &quot;【專家直斷】&quot;">​</a></h2><p><strong>良維處於「高經營槓桿轉折期」— 固定成本佔比約 13-15% (屬中高槓桿)，2025 年產能利用率約 70-80%，獲利彈性為「爆發型」特徵。</strong></p><ul><li><strong>槓桿特徵</strong>：DOL ≈ 5.8x，固定成本 (D&amp;A + 核心薪資 + 固定管銷) 估算約 12-15 億，佔營收比約 12-15%。</li><li><strong>產能利用率</strong>：泰國新廠為主擴產基地，當前利用率約 70-80% (接近產能甜蜜點)。</li><li><strong>獲利彈性</strong>：營收成長 34.7% (FY2025 YoY) → 營業利益成長 201.8%，展現極高經營槓桿。</li><li><strong>生存壓力點</strong>：損益平衡營收約落在 38-40 億元，僅為 FY2025 營收的 38%，安全邊際充裕 (62%)。</li><li><strong>資本重載風險</strong>：固定資產 (PPE) 自 2023Q4 的 11.0 億擴增至 2025Q4 的 18.0 億 (+63.5%)，折舊年增率 14.5%，屬合理擴張範疇。</li></ul><hr><h2 id="【診斷評級】" tabindex="-1">【診斷評級】 <a class="header-anchor" href="#【診斷評級】" aria-label="Permalink to &quot;【診斷評級】&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">評分</th><th style="text-align:left;">評語</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>A (良)</strong></td><td style="text-align:left;">成本結構平衡，變動成本 (COGS) 佔營收比約 68.6%，賦予營收下行時自動裁減的防禦彈性。D&amp;A/營收僅 2.18%，折舊負擔輕。固定成本可控，獲利爆發特徵已在 FY2025 充分展現。泰國廠利用率若進一步提升至 85%+，DOL 將啟動更強勁的獲利加速效應。</td></tr></tbody></table><hr><h2 id="【答詢詳解】" tabindex="-1">【答詢詳解】 <a class="header-anchor" href="#【答詢詳解】" aria-label="Permalink to &quot;【答詢詳解】&quot;">​</a></h2><h3 id="一、營運成本習性拆解-cost-behavior-analysis" tabindex="-1">一、營運成本習性拆解 (Cost Behavior Analysis) <a class="header-anchor" href="#一、營運成本習性拆解-cost-behavior-analysis" aria-label="Permalink to &quot;一、營運成本習性拆解 (Cost Behavior Analysis)&quot;">​</a></h3><h4 id="_1-1-fy2025-成本結構總覽" tabindex="-1">1.1 FY2025 成本結構總覽 <a class="header-anchor" href="#_1-1-fy2025-成本結構總覽" aria-label="Permalink to &quot;1.1 FY2025 成本結構總覽&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">成本項目</th><th style="text-align:center;">金額 (億元)</th><th style="text-align:center;">佔營收比</th><th style="text-align:left;">成本習性</th></tr></thead><tbody><tr><td style="text-align:left;">營業收入</td><td style="text-align:center;">101.6</td><td style="text-align:center;">100.0%</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:left;">營業成本 (COGS)</td><td style="text-align:center;">69.7</td><td style="text-align:center;">68.6%</td><td style="text-align:left;">變動 (原物料+直接人工)</td></tr><tr><td style="text-align:left;">營業毛利</td><td style="text-align:center;">31.9</td><td style="text-align:center;">31.4%</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:left;">營業費用</td><td style="text-align:center;">14.2</td><td style="text-align:center;">14.0%</td><td style="text-align:left;">混合</td></tr><tr><td style="text-align:left;">— 折舊與攤銷 (D&amp;A)</td><td style="text-align:center;">2.22</td><td style="text-align:center;">2.2%</td><td style="text-align:left;">固定</td></tr><tr><td style="text-align:left;">— 推銷費用 (估)</td><td style="text-align:center;">~4.3</td><td style="text-align:center;">~4.2%</td><td style="text-align:left;">半變動 (隨營收變動)</td></tr><tr><td style="text-align:left;">— 管理費用 (估)</td><td style="text-align:center;">~5.6</td><td style="text-align:center;">~5.5%</td><td style="text-align:left;">固定+半固定</td></tr><tr><td style="text-align:left;">— 研發費用 (估)</td><td style="text-align:center;">~4.3</td><td style="text-align:center;">~4.2%</td><td style="text-align:left;">固定</td></tr><tr><td style="text-align:left;">營業利益</td><td style="text-align:center;">17.7</td><td style="text-align:center;">17.4%</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:left;">固定成本合計 (D&amp;A+固定管銷+核心薪資)</td><td style="text-align:center;">~13-15</td><td style="text-align:center;">~12-15%</td><td style="text-align:left;">固定</td></tr><tr><td style="text-align:left;">變動成本合計 (COGS+變動管銷)</td><td style="text-align:center;">~72-74</td><td style="text-align:center;">~71-73%</td><td style="text-align:left;">變動</td></tr><tr><td style="text-align:left;"><strong>邊際貢獻率 (CM Ratio)</strong></td><td style="text-align:center;"><strong>~24.4%</strong></td><td style="text-align:center;">—</td><td style="text-align:left;">—</td></tr></tbody></table><h4 id="_1-2-成本習性解讀" tabindex="-1">1.2 成本習性解讀 <a class="header-anchor" href="#_1-2-成本習性解讀" aria-label="Permalink to &quot;1.2 成本習性解讀&quot;">​</a></h4><ul><li><strong>變動成本主導</strong>：COGS (原物料+直接人工) 佔營收 68.6%，屬典型製造業結構。營收增減時 COGS 隨之同向變動，提供基本的景氣緩衝。</li><li><strong>固定成本輕量化</strong>：D&amp;A 僅佔營收 2.2%，在製造業中偏低。核心固定成本 (D&amp;A+核心薪資+固定管銷) 佔營收 12-15%，屬健康區間。</li><li><strong>費用結構健康</strong>：營業費用率 14.0% = 推銷 (4.2%) + 管理 (5.5%) + 研發 (4.2%)。研發費用佔比穩定，顯示公司未因擴產而犧牲技術投入。</li><li><strong>規模經濟優勢</strong>：FY2024 至 FY2025 的營收成長 34.7% 帶動毛利率從 19.1% 躍升至 31.4%，OPM 從 7.8% 跳升至 17.4%，充分展現固定成本被營收稀釋的槓桿效應。</li></ul><h3 id="二、規模經濟臨界檢核-scalability-threshold" tabindex="-1">二、規模經濟臨界檢核 (Scalability Threshold) <a class="header-anchor" href="#二、規模經濟臨界檢核-scalability-threshold" aria-label="Permalink to &quot;二、規模經濟臨界檢核 (Scalability Threshold)&quot;">​</a></h3><h4 id="_2-1-損益平衡點分析" tabindex="-1">2.1 損益平衡點分析 <a class="header-anchor" href="#_2-1-損益平衡點分析" aria-label="Permalink to &quot;2.1 損益平衡點分析&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">參數</th><th style="text-align:center;">數值</th></tr></thead><tbody><tr><td style="text-align:left;">固定成本估算 (年)</td><td style="text-align:center;">~9.3 億元 (含 D&amp;A + 固定管銷)</td></tr><tr><td style="text-align:left;">邊際貢獻率</td><td style="text-align:center;">~24.4%</td></tr><tr><td style="text-align:left;"><strong>損益平衡營收</strong></td><td style="text-align:center;"><strong>~38.3 億元</strong></td></tr><tr><td style="text-align:left;">當前營收 (FY2025)</td><td style="text-align:center;">101.6 億元</td></tr><tr><td style="text-align:left;"><strong>安全邊際</strong></td><td style="text-align:center;"><strong>62.3%</strong></td></tr></tbody></table><blockquote><p><strong>解讀</strong>：良維的損益平衡點僅需 38.3 億元營收即可打平所有固定成本。FY2025 營收 101.6 億元遠高於此門檻，意味著超過 62% 的營收直接轉化為利潤貢獻。即便每月營收驟降至 3.2 億元以下 (目前約 8.5 億/月)，公司仍能維持獲利。</p></blockquote><h4 id="_2-2-獲利加速器水閘-scale-sweet-spot" tabindex="-1">2.2 獲利加速器水閘 (Scale Sweet Spot) <a class="header-anchor" href="#_2-2-獲利加速器水閘-scale-sweet-spot" aria-label="Permalink to &quot;2.2 獲利加速器水閘 (Scale Sweet Spot)&quot;">​</a></h4><p>根據當前邊際貢獻率與固定成本結構，計算營收規模對 OPM 的非線性影響：</p><table tabindex="0"><thead><tr><th style="text-align:center;">營收規模 (億元)</th><th style="text-align:center;">邊際貢獻 (億元)</th><th style="text-align:center;">固定成本 (億元)</th><th style="text-align:center;">OI (億元)</th><th style="text-align:center;">OPM</th></tr></thead><tbody><tr><td style="text-align:center;">40</td><td style="text-align:center;">9.8</td><td style="text-align:center;">9.3</td><td style="text-align:center;">0.5</td><td style="text-align:center;">1.2%</td></tr><tr><td style="text-align:center;">60</td><td style="text-align:center;">14.7</td><td style="text-align:center;">9.3</td><td style="text-align:center;">5.4</td><td style="text-align:center;">9.0%</td></tr><tr><td style="text-align:center;">80</td><td style="text-align:center;">19.5</td><td style="text-align:center;">9.3</td><td style="text-align:center;">10.2</td><td style="text-align:center;">12.8%</td></tr><tr><td style="text-align:center;"><strong>100</strong></td><td style="text-align:center;"><strong>24.4</strong></td><td style="text-align:center;"><strong>9.3</strong></td><td style="text-align:center;"><strong>15.1</strong></td><td style="text-align:center;"><strong>15.1%</strong></td></tr><tr><td style="text-align:center;">120</td><td style="text-align:center;">29.3</td><td style="text-align:center;">9.3</td><td style="text-align:center;">20.0</td><td style="text-align:center;">16.7%</td></tr><tr><td style="text-align:center;">140</td><td style="text-align:center;">34.2</td><td style="text-align:center;">9.3</td><td style="text-align:center;">24.9</td><td style="text-align:center;">17.8%</td></tr></tbody></table><blockquote><p><strong>加速臨界點位於營收 60-80 億元</strong>：當營收跨越 60 億元，OPM 開始顯著加速；跨越 80 億元後，每增加 20 億營收約可挹注 4.9 億的營業利益增量。FY2025 的 101.6 億已穩居加速區。</p></blockquote><h3 id="三、景氣承壓測試-cyclical-stress-test" tabindex="-1">三、景氣承壓測試 (Cyclical Stress Test) <a class="header-anchor" href="#三、景氣承壓測試-cyclical-stress-test" aria-label="Permalink to &quot;三、景氣承壓測試 (Cyclical Stress Test)&quot;">​</a></h3><h4 id="_3-1-營收下降對獲利的非線性衝擊" tabindex="-1">3.1 營收下降對獲利的非線性衝擊 <a class="header-anchor" href="#_3-1-營收下降對獲利的非線性衝擊" aria-label="Permalink to &quot;3.1 營收下降對獲利的非線性衝擊&quot;">​</a></h4><p>基於 FY2025 的邊際貢獻率 24.4% 與固定成本 9.3 億：</p><table tabindex="0"><thead><tr><th style="text-align:center;">情境</th><th style="text-align:center;">營收衝擊</th><th style="text-align:center;">營收 (億元)</th><th style="text-align:center;">OI (億元)</th><th style="text-align:center;">OI 變化</th></tr></thead><tbody><tr><td style="text-align:center;">基準</td><td style="text-align:center;">0%</td><td style="text-align:center;">101.6</td><td style="text-align:center;">15.5</td><td style="text-align:center;">—</td></tr><tr><td style="text-align:center;">輕度衰退</td><td style="text-align:center;">-10%</td><td style="text-align:center;">91.4</td><td style="text-align:center;">13.0</td><td style="text-align:center;">-16%</td></tr><tr><td style="text-align:center;">中度衰退</td><td style="text-align:center;">-20%</td><td style="text-align:center;">81.3</td><td style="text-align:center;">10.5</td><td style="text-align:center;">-32%</td></tr><tr><td style="text-align:center;">重度衰退</td><td style="text-align:center;">-30%</td><td style="text-align:center;">71.1</td><td style="text-align:center;">8.0</td><td style="text-align:center;">-48%</td></tr></tbody></table><blockquote><p><strong>高敏感度判定</strong>：營收每下降 10%，營業利益縮減約 16%。若營收下降 20%，獲利將縮減 32%；營收下降 30%，獲利近乎腰斬 (-48%)。</p><p><strong>結論</strong>：營收對淨利的放大倍率約 1.6x (每 -10% 營收 → -16% 獲利)。相較於典型高槓桿製造業 (2-3x)，良維的放大倍率偏低，主因是固定成本佔比不大 (D&amp;A/營收僅 2.2%)，槓桿主要來自管銷費用的固定性，而非折舊。</p></blockquote><h4 id="_3-2-營收恢復彈性" tabindex="-1">3.2 營收恢復彈性 <a class="header-anchor" href="#_3-2-營收恢復彈性" aria-label="Permalink to &quot;3.2 營收恢復彈性&quot;">​</a></h4><p>若營收從 FY2024 的 75.4 億回升至 FY2025 的 101.6 億，營業利益從 5.9 億暴增至 17.7 億 (+201.8%)，<strong>呈現典型的高恢復彈性</strong>。這意味著：</p><ol><li>營收恢復時獲利倍速反彈</li><li>泰國廠產能利用率從偏低水準回升至 70-80% 的過程中，折舊覆蓋率大幅改善</li><li>2025 年的費用結構已受益於規模效應舒緩</li></ol><hr><h2 id="【證據來源】數據溯源" tabindex="-1">【證據來源】數據溯源 <a class="header-anchor" href="#【證據來源】數據溯源" aria-label="Permalink to &quot;【證據來源】數據溯源&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">數據項</th><th style="text-align:center;">數值</th><th style="text-align:left;">來源</th></tr></thead><tbody><tr><td style="text-align:left;">FY2025 合併營收</td><td style="text-align:center;">101.6 億元</td><td style="text-align:left;">FinMind: Revenue (四季度總和: 23.41+26.13+25.30+26.74 億)</td></tr><tr><td style="text-align:left;">FY2024 合併營收</td><td style="text-align:center;">75.4 億元</td><td style="text-align:left;">FinMind: Revenue (四季度總和)</td></tr><tr><td style="text-align:left;">FY2025 營業毛利</td><td style="text-align:center;">31.9 億元 (GM 31.42%)</td><td style="text-align:left;">FinMind: GrossProfit</td></tr><tr><td style="text-align:left;">FY2025 營業費用</td><td style="text-align:center;">14.2 億元</td><td style="text-align:left;">FinMind: OperatingExpenses</td></tr><tr><td style="text-align:left;">FY2025 營業利益</td><td style="text-align:center;">17.7 億元 (OPM 17.40%)</td><td style="text-align:left;">計算: GrossProfit - OperatingExpenses</td></tr><tr><td style="text-align:left;">FY2025 折舊費用</td><td style="text-align:center;">2.07 億元</td><td style="text-align:left;">FinMind 現金流量表: Depreciation (2025Q4 累計值)</td></tr><tr><td style="text-align:left;">FY2025 攤銷費用</td><td style="text-align:center;">0.15 億元</td><td style="text-align:left;">FinMind 現金流量表: AmortizationExpense (2025Q4 累計值)</td></tr><tr><td style="text-align:left;">PPE 2025Q4</td><td style="text-align:center;">18.0 億元</td><td style="text-align:left;">FinMind 資產負債表: PropertyPlantAndEquipment</td></tr><tr><td style="text-align:left;">PPE 2023Q4</td><td style="text-align:center;">11.0 億元</td><td style="text-align:left;">FinMind 資產負債表 (同科目)</td></tr><tr><td style="text-align:left;">D&amp;A/營收比</td><td style="text-align:center;">2.18%</td><td style="text-align:left;">計算: 2.22億/101.6億</td></tr><tr><td style="text-align:left;">FY2025 EPS</td><td style="text-align:center;">8.72 元</td><td style="text-align:left;">FinMind: EPS 四季度加總</td></tr><tr><td style="text-align:left;">FY2024 EPS</td><td style="text-align:center;">4.98 元</td><td style="text-align:left;">FinMind: EPS 四季度加總</td></tr><tr><td style="text-align:left;">DOL (FY2024→FY2025)</td><td style="text-align:center;">5.81x</td><td style="text-align:left;">計算: 營業利益成長 201.8% / 營收成長 34.7%</td></tr><tr><td style="text-align:left;">損益平衡營收</td><td style="text-align:center;">~38.3 億元</td><td style="text-align:left;">計算: 固定成本 9.3 億 / CM Ratio 24.4%</td></tr><tr><td style="text-align:left;">海內外產能利用率</td><td style="text-align:center;">70-80%</td><td style="text-align:left;">公司年報 / 法說會資料 (泰國廠為擴產重心)</td></tr><tr><td style="text-align:left;">FY2026 Q1營收</td><td style="text-align:center;">25.4 億元</td><td style="text-align:left;">FinMind: 月營收 (2026年1-3月加總)</td></tr></tbody></table><hr><h2 id="【專家評析】" tabindex="-1">【專家評析】 <a class="header-anchor" href="#【專家評析】" aria-label="Permalink to &quot;【專家評析】&quot;">​</a></h2><h3 id="核心洞察-成本結構為「擴張跳板」而非「沉重枷鎖」" tabindex="-1">核心洞察：成本結構為「擴張跳板」而非「沉重枷鎖」 <a class="header-anchor" href="#核心洞察-成本結構為「擴張跳板」而非「沉重枷鎖」" aria-label="Permalink to &quot;核心洞察：成本結構為「擴張跳板」而非「沉重枷鎖」&quot;">​</a></h3><h4 id="_1-高經營槓桿的正反饋已啟動" tabindex="-1">1. 高經營槓桿的正反饋已啟動 <a class="header-anchor" href="#_1-高經營槓桿的正反饋已啟動" aria-label="Permalink to &quot;1. 高經營槓桿的正反饋已啟動&quot;">​</a></h4><p>良維的 DOL 達 5.81x，雖然看起來數值極高，但這是在 FY2025 營收 YoY+34.7% 的基礎上獲取的。高 DOL 本身中性——在營收上升期是「獲利噴射引擎」，在營收衰退時則是「獲利侵蝕加速器」。良維當前處於營收成長週期的上升段 (FY2026 Q1 營收 25.4 億，年化約 101.6 億，維持高檔)，因此 DOL 正在產生正反饋。</p><h4 id="_2-折舊負擔不構成威脅" tabindex="-1">2. 折舊負擔不構成威脅 <a class="header-anchor" href="#_2-折舊負擔不構成威脅" aria-label="Permalink to &quot;2. 折舊負擔不構成威脅&quot;">​</a></h4><p>關鍵證據：D&amp;A/營收比僅 2.18%，遠低於一般製造業的 4-8%。這說明：</p><ul><li>良維的資產週轉效率高 (PPE/營收比約 17.7%)</li><li>泰國廠的擴產採用階段性投資，未一次性過度資本支出</li><li>即使產能利用率維持 70-80%，折舊已被營收充分覆蓋</li></ul><h4 id="_3-變動成本結構提供充分防禦緩衝" tabindex="-1">3. 變動成本結構提供充分防禦緩衝 <a class="header-anchor" href="#_3-變動成本結構提供充分防禦緩衝" aria-label="Permalink to &quot;3. 變動成本結構提供充分防禦緩衝&quot;">​</a></h4><p>COGS 佔營收 68.6% 意味著超過 2/3 的成本隨營收變動。當需求下滑時，原物料採購可自動縮減，賦予公司在景氣下行時快速調整的彈性。這與題本警示的「固定成本極高且產能利用率長期低於 65%」的 B 級風險場景完全不符。</p><h4 id="_4-折舊年限變動檢查" tabindex="-1">4. 折舊年限變動檢查 <a class="header-anchor" href="#_4-折舊年限變動檢查" aria-label="Permalink to &quot;4. 折舊年限變動檢查&quot;">​</a></h4><p>FY2023 D&amp;A = 2.49 億 &gt; FY2024 D&amp;A = 1.94 億 &gt; FY2025 D&amp;A = 2.22 億。FY2024 折舊因部分設備折舊完畢而下降，FY2025 隨泰國廠投產而回升，呈正常折舊軌跡。<strong>未發現突發性拉長折舊年限的財務粉飾跡象</strong>。</p><h4 id="_5-擴張階段風險預警" tabindex="-1">5. 擴張階段風險預警 <a class="header-anchor" href="#_5-擴張階段風險預警" aria-label="Permalink to &quot;5. 擴張階段風險預警&quot;">​</a></h4><ul><li><strong>泰國廠利用率若無法提升至 85%+</strong>：PPE 已從 11.0 億擴充至 18.0 億，若下游需求放緩導致泰國廠利用率長期低於 70%，新增折舊將開始侵蝕獲利。目前 70-80% 的利用率處在臨界區邊緣。</li><li><strong>FY2026 營收動能需保持</strong>：FY2026 Q1 營收 25.4 億，YoY+8.5% (對比 FY2025 Q1 的 23.4 億)。若全年營收能達 110 億以上，DOL 將持續提供獲利加速。</li><li><strong>建議關注月度 YoY 趨勢</strong>：FY2026 前三個月 YoY 增幅已放緩至個位數，需留意成長動能是否減速。</li></ul><h4 id="_6-綜合判定" tabindex="-1">6. 綜合判定 <a class="header-anchor" href="#_6-綜合判定" aria-label="Permalink to &quot;6. 綜合判定&quot;">​</a></h4><blockquote><p><strong>擴張的跳板 (Expansion Trampoline)</strong>：良維處於典型的「規模經濟紅利收割期」。固定資產投資已於 2023-2025 年完成 (PPE +63.5%)，D&amp;A/營收僅 2.2% 的輕負荷結構與 62% 的安全邊際，確保了即使面臨 20% 的營收下行，公司仍能維持正向獲利。泰國廠產能利用率若從 70% 進一步提升至 85-90%，將啟動下一階段的獲利加速。當前成本結構是優秀的「成長型槓桿」，而非題本警示的「資本重載陷阱」。</p></blockquote><hr><p><strong>報告撰寫</strong>：Deep32Q 財務分析專家 (L3) <strong>數據時點</strong>：截至 2026-04-24 已公告財報數據 <strong>存檔路徑</strong>：<code>/Users/kaipro/.openclaw/skills/NEW_Deep32Q/審計報告庫/6290_良維/20260424/財務組/F10_成本結構與經營槓桿門檻_財務分析專家.md</code></p>',53)])])}const h=e(r,[["render",d]]);export{c as __pageData,h as default};
